/* ── Bottom Navigation (Mobile Only) ── */
.cb-bottom-nav {
  display: none;
  position: fixed; bottom: 0; left: 0; right: 0;
  height: 56px;
  background: var(--cb-glass-bg);
  backdrop-filter: var(--cb-glass-blur);
  -webkit-backdrop-filter: var(--cb-glass-blur);
  border-top: 1px solid var(--cb-border);
  z-index: 200;
  flex-direction: row; align-items: stretch;
}
.cb-bottom-nav-item {
  flex: 1; display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  gap: 3px; cursor: pointer; color: var(--cb-text-muted);
  transition: color 0.2s; min-width: 44px;
}
.cb-bottom-nav-item.active { color: var(--cb-red); }
.cb-bottom-nav-item:hover { color: var(--cb-text); }
.cb-bottom-nav-item svg {
