  stroke: currentColor; fill: none;
  stroke-width: 1.5; stroke-linecap: round; stroke-linejoin: round;
}
.cb-bottom-nav-label { font-size: 10px; font-weight: 600; letter-spacing: 0.3px; }

/* ── Modals ── */
.cb-modal-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.75); backdrop-filter: blur(6px);
  display: flex; align-items: center; justify-content: center;
  z-index: 300; padding: 16px;
}
.cb-modal-box {
  background: var(--cb-bg3); border: 1px solid var(--cb-border);
  border-radius: 16px; width: 100%; max-width: 520px; max-height: 85vh;
  overflow-y: auto; padding: 28px; position: relative;
  box-shadow: 0 20px 60px rgba(0,0,0,0.6);
  animation: modalSlideIn 0.25s ease;
}
@keyframes modalSlideIn {
  from { opacity: 0; transform: translateY(20px) scale(0.96); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}
.cb-modal-close {
  position: absolute; top: 14px; right: 14px;
  background: rgba(255,255,255,0.08); border: none;
  color: var(--cb-text); width: 30px; height: 30px;
  border-radius: 50%; cursor: pointer; font-size: 14px;
  display: flex; align-items: center; justify-content: center;
  transition: background 0.2s;
}
.cb-modal-close:hover { background: rgba(255,255,255,0.15); }
.cb-modal-title { font-size: 18px; font-weight: 700; color: #fff; margin: 0 0 6px; }
.cb-modal-sub { font-size: 13px; color: var(--cb-text-muted); margin: 0 0 20px; }
.cb-modal-loading { text-align: center; padding: 30px; color: var(--cb-text-muted); }
.cb-modal-empty { text-align: center; padding: 30px; color: var(--cb-text-muted); line-height: 1.6; }

.cb-cinema-list { display: flex; flex-direction: column; gap: 10px; }
