.cb-cinema-icon { font-size: 20px; }
.cb-cinema-name { font-weight: 600; font-size: 14px; color: #fff; }
.cb-cinema-addr { font-size: 12px; color: var(--cb-text-muted); margin-top: 2px; }

.cb-contact-list { display: flex; flex-direction: column; gap: 12px; }
.cb-contact-item { display: flex; align-items: center; gap: 14px; padding: 14px 16px; background: rgba(255,255,255,0.04); border-radius: 10px; }
.cb-contact-icon { font-size: 20px; }
.cb-contact-label { font-size: 11px; color: var(--cb-text-muted); margin-bottom: 3px; }
.cb-contact-value { font-size: 14px; font-weight: 600; color: #fff; }

.cb-news-list { display: flex; flex-direction: column; gap: 12px; }
