.cb-news-emoji { font-size: 22px; flex-shrink: 0; }
.cb-news-body {}
.cb-news-title { font-weight: 700; font-size: 14px; color: #fff; margin-bottom: 3px; }
.cb-news-date { font-size: 11px; color: var(--cb-text-muted); margin-bottom: 4px; }
.cb-news-desc { font-size: 12px; color: rgba(236,236,236,0.65); }

.cb-rent-form { display: flex; flex-direction: column; gap: 14px; }
.cb-form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.cb-form-group { display: flex; flex-direction: column; gap: 6px; }
.cb-form-group label { font-size: 12px; font-weight: 600; color: var(--cb-text-muted); }
.cb-form-group input,
.cb-form-group textarea {
